import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from "react-router-dom";

import Login from "./Login";
import Register from "./Register";
import Home from "./Home";
import NewPrediction from "./NewPrediction";
import AdminLogin from "./AdminLogin";
import MyPredictionHistory from "./MyPredictionHistory";
import AverageSalary from "./AverageSalary";
import AdminDashboard from "./AdminDashboard";

// 🔐 Protected Route for USER
const ProtectedRoute = ({ children }) => {
  const user = localStorage.getItem("user");
  return user ? children : <Navigate to="/login" />;
};

// 🔐 Protected Route for ADMIN
const AdminProtectedRoute = ({ children }) => {
  const admin = localStorage.getItem("admin");
  return admin ? children : <Navigate to="/adminlogin" />;
};

function App() {
  return (
    <Router>
      <Routes>

        {/* Default */}
        <Route path="/" element={<Login />} />

        {/* User Auth */}
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />

        {/* User Pages */}
        <Route path="/home" element={
          <ProtectedRoute>
            <Home />
          </ProtectedRoute>
        } />

        <Route path="/predict" element={
          <ProtectedRoute>
            <NewPrediction />
          </ProtectedRoute>
        } />
<Route path="/average-salary" element={<AverageSalary />} />
        <Route path="/my-history" element={
          <ProtectedRoute>
            <MyPredictionHistory />
          </ProtectedRoute>
        } />
        <Route path="/adminlogin" element={<AdminLogin />} />
        <Route path="/admindashboard" element={
          <AdminProtectedRoute>
            <AdminDashboard />
          </AdminProtectedRoute>
        } />

      </Routes>
    </Router>
  );
}

export default App;
